import{p as o,bx as r,bh as i,I as l,U as s,A as a,W as e,X as d}from"./chunks/framework.BpabEsSf.js";const _=JSON.parse('{"title":"Технический документ по локальному хранению и шифрованию","description":"","frontmatter":{"title":"Технический документ по локальному хранению и шифрованию","date":"2026-05-16T13:15:00.000Z","permalink":"/reference/android-storage-security","categories":["Technical Insights"],"tags":["Android","Security","Encryption"]},"headers":[],"relativePath":"ru/02.Configuration/02.Docs/02.Monica Android Local Storage & Encryption Tech Doc.md","filePath":"ru/02.Configuration/02.Docs/02.Monica Android Local Storage & Encryption Tech Doc.md","lastUpdated":null}'),p={name:"ru/02.Configuration/02.Docs/02.Monica Android Local Storage & Encryption Tech Doc.md"};function c(u,n,b,h,m,g){const t=r("Badge");return i(),l("div",null,[n[7]||(n[7]=s('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /ru\\02.Configuration\\02.Docs\\02.Monica Android Local Storage &amp; Encryption Tech Doc.md for this page in Markdown format</div><h1 id="🔒-техническии-документ-по-локальному-хранению-и-шифрованию-monica-android" tabindex="-1">🔒 Технический документ по локальному хранению и шифрованию Monica Android <a class="header-anchor" href="#🔒-техническии-документ-по-локальному-хранению-и-шифрованию-monica-android" aria-label="Permalink to &quot;🔒 Технический документ по локальному хранению и шифрованию Monica Android&quot;">​</a></h1><div class="note custom-block"><p class="title note-title custom-block-title">Архитектура Zero-Knowledge</p><p><code>Monica Android</code> использует многоуровневую архитектуру каскадного шифрования на уровне всего диска и отдельных полей базы данных для обеспечения абсолютной безопасности конфиденциальных активов пользователей (таких как пароли, номера кредитных карт, ключи 2FA, защищенные заметки и т. д.) во время локального хранения и процедур резервного копирования WebDAV. Ядро системы строго соответствует концепции <strong>Архитектуры Zero-Knowledge (Нулевого разглашения)</strong>: даже если устройство будет утеряно или файлы базы данных будут извлечены, злоумышленник не сможет восстановить какие-либо открытые данные без Мастер-пароля пользователя.</p></div><hr><h2 id="_1-локальное-хранение-данных" tabindex="-1">1. Локальное хранение данных <a class="header-anchor" href="#_1-локальное-хранение-данных" aria-label="Permalink to &quot;1. Локальное хранение данных&quot;">​</a></h2><p>Monica отказывается от хранения данных в открытом виде в SQLite или от использования ненадежных конфигураций ключ-значение, полностью перенимая рекомендованные Google архитектурные практики <strong>Modern Android Development (MAD)</strong> для управления структурированными данными:</p>',6)),a("ul",null,[n[5]||(n[5]=a("li",null,[a("strong",null,"Основной уровень сохраняемости"),e(": Реализован с помощью библиотеки "),a("code",null,"Room Persistence Library"),e(" (продвинутый уровень абстракции над SQLite) для поддержания высокосвязных объектов доступа к данным (DAO).")],-1)),n[6]||(n[6]=a("li",null,[a("strong",null,"Физическая инфраструктура файлов"),e(": Данные записываются непосредственно в изолированный песочницей файл "),a("code",null,"password_database.db"),e(" и связанные с ним WAL-файлы (Write-Ahead Logging).")],-1)),a("li",null,[n[0]||(n[0]=a("strong",null,"Граница физической изоляции",-1)),n[1]||(n[1]=e()),d(t,{text:"Изоляция",type:"info"}),n[2]||(n[2]=e(": База данных хранится исключительно по внутреннему системному пути приложения (",-1)),n[3]||(n[3]=a("code",null,"/data/data/com.joyinjoester.monica/databases/",-1)),n[4]||(n[4]=e("), защищенному UID-изоляцией на уровне ядра Linux в ОС Android. Доступ к этой директории сторонним приложениям без Root-привилегий строго заблокирован.",-1))])]),n[8]||(n[8]=s(`<hr><h2 id="_2-механизм-деривации-ключеи-верхнего-уровня-kdf" tabindex="-1">2. Механизм деривации ключей верхнего уровня (KDF) <a class="header-anchor" href="#_2-механизм-деривации-ключеи-верхнего-уровня-kdf" aria-label="Permalink to &quot;2. Механизм деривации ключей верхнего уровня (KDF)&quot;">​</a></h2><p>Для предотвращения компрометации локальных данных в результате атак методом перебора (брутфорса) или по радужным таблицам при утечке файлов базы данных, <code>Monica</code> использует строгий стандарт криптографической деривации ключей:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ Мастер-пароль пользователя ] ➔ Ввод в рантайме</span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[ Функция деривации PBKDF2 ] 🔀 Инъекция высокоэнтропийной соли (Salt)</span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[ 100 000 итераций хэширования HMAC-SHA256 ] ➔ Выравнивание вычислительной сложности</span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[ Сгенерированный промежуточный ключ растяжения ] ➔ 256-битный симметричный ключ</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><ol><li><strong>Динамическая соль</strong>: При первой инициализации хранилища генератор случайных чисел криптографического уровня (<code>SecureRandom</code>) создает уникальную 128-битную соль. Эта соль сохраняется в открытом виде в системных настройках, гарантируя, что одинаковые Мастер-пароли на разных устройствах породят совершенно разные итоговые ключи.</li><li><strong>Растяжение ключа</strong>: Алгоритм <code>PBKDF2</code> выполняет <strong>100 000 итераций</strong> хэширования с использованием <code>HMAC-SHA256</code>, искусственно увеличивая вычислительные затраты на генерацию одного ключа. Это делает попытки подбора пароля на специализированном оборудовании (GPU/ASIC) экономически неэффективными.</li></ol><hr><h2 id="_3-аппаратная-защита-ключеи-и-рантаима" tabindex="-1">3. Аппаратная защита ключей и рантайма <a class="header-anchor" href="#_3-аппаратная-защита-ключеи-и-рантаима" aria-label="Permalink to &quot;3. Аппаратная защита ключей и рантайма&quot;">​</a></h2><p>Деривированный 256-битный ключ не используется напрямую для шифрования базы данных. Вместо этого Monica внедряет схему двухслойного конвертного шифрования (Envelope Encryption), опирающуюся на аппаратную архитектуру безопасности Android:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ Системный Android KeyStore ] ➔ Изоляция внутри среды TEE / SE</span></span>
<span class="line"><span>       ⬇ Нативная генерация</span></span>
<span class="line"><span>[ Аппаратный ключ шифрования ключей (KEK) ] </span></span>
<span class="line"><span>       ⬇ Защита на уровне рантайма</span></span>
<span class="line"><span>[ Зашифрованный локальный ключ данных (DEK) ] ➔ Шифрует реальные поля базы данных</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="хранилище-android-keystore" tabindex="-1">Хранилище Android KeyStore <a class="header-anchor" href="#хранилище-android-keystore" aria-label="Permalink to &quot;Хранилище Android KeyStore&quot;">​</a></h3><p>Monica генерирует уникальный ключ шифрования ключей (KEK) непосредственно внутри <strong><code>Android KeyStore</code></strong>. Этот ключ аппаратно изолирован в доверенной среде выполнения (<strong>TEE — Trusted Execution Environment</strong>) или на выделенном чипе безопасности (<strong>SE — Secure Element</strong>, таком как чипы Titan на устройствах Pixel).</p><ul><li>Операционная система Android и прикладной код Monica могут отправлять данные в KeyStore для выполнения криптографических операций, но <strong>сам KEK никогда не может быть извлечен в память рантайма в открытом виде</strong>.</li><li>Доступ к операциям KeyStore дополнительно защищен системными компонентами <code>EncryptedSharedPreferences</code> и аутентификацией <code>BiometricPrompt</code> (сканером отпечатков пальцев).</li></ul><h3 id="конвертное-шифрования-полеи-field-level-encryption" tabindex="-1">Конвертное шифрования полей (Field-Level Encryption) <a class="header-anchor" href="#конвертное-шифрования-полеи-field-level-encryption" aria-label="Permalink to &quot;Конвертное шифрования полей (Field-Level Encryption)&quot;">​</a></h3><p>Реальный ключ шифрования данных (DEK), используемый для обработки информации в базе данных, упакован с помощью KEK. При чтении или записи данных приложение отправляет зашифрованный DEK в KeyStore, получает расшифрованную копию в защищенную область памяти рантайма для проведения быстрых потоковых операций <strong>AES-256-GCM</strong>, а затем немедленно очищает массивы байтов памяти для предотвращения атак со сбросом дампов памяти.</p><hr><h2 id="_4-спецификация-облачного-зашифрованного-транспортного-конвеиера" tabindex="-1">4. Спецификация облачного зашифрованного транспортного конвейера <a class="header-anchor" href="#_4-спецификация-облачного-зашифрованного-транспортного-конвеиера" aria-label="Permalink to &quot;4. Спецификация облачного зашифрованного транспортного конвейера&quot;">​</a></h2><p>При запуске пользователем резервного копирования в облако WebDAV, система активирует изолированный конвейер шифрования пакетов под названием <code>MONICA_ENC_V1</code> для предотвращения компрометации данных провайдерами облачных услуг.</p><div class="center tk-center-container"><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ Конвейер упаковки резервных копий ]</span></span>
<span class="line"><span>[ Основные JSON-пакеты песочницы ] </span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[ Упаковка в стандартный бинарный поток ZIP ] </span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[ Запрос пароля бэкапа ] ➔ [ Деривация ключа через PBKDF2 (100k итераций) ]</span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[ Инъекция усиленного шифрования AES-256-GCM ] </span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[ Добавление магического заголовка MONICA_ENC_V1 ] ➔ Создание файла .enc.zip ➔ Загрузка по WebDAV</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div></div><ul><li><strong>Защита от воспроизведения и декорреляция</strong>: Каждый экземпляр резервной копии независимо генерирует высокоэнтропийные соли и уникальные векторы инициализации (IV). Даже если содержимое бэкапов идентично, бинарные структуры результирующих архивов <code>.enc.zip</code> в облаке будут полностью отличаться, что исключает возможность профилирования пользовательских данных провайдерами облака по размеру цифрового отпечатка файла.</li></ul><hr><h2 id="_5-сводная-матрица-криптографическои-безопасности" tabindex="-1">5. Сводная матрица криптографической безопасности <a class="header-anchor" href="#_5-сводная-матрица-криптографическои-безопасности" aria-label="Permalink to &quot;5. Сводная матрица криптографической безопасности&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Уровень безопасности</th><th>Техническая реализация</th><th>Целевые векторы угроз</th></tr></thead><tbody><tr><td><strong>Локальное хранение данных</strong></td><td><code>AES-256-GCM (256-бит)</code></td><td>Атаки с извлечением базы данных, физическое изменение бит на диске, сайдчейн-инъекции</td></tr><tr><td><strong>Защита Мастер-пароля</strong></td><td><code>PBKDF2 + HMAC-SHA256</code> (100 000 итераций)</td><td>Оффлайн-перебор (брутфорс), совпадение по радужным таблицам, распыление словарей</td></tr><tr><td><strong>Защита ключей в рантайме</strong></td><td><code>Android KeyStore</code> (Границы TEE/SE)</td><td>Дампы памяти, обход границ файлов с Root-привилегиями, физическое снятие слоев чипа</td></tr><tr><td><strong>Облачный транспорт данных</strong></td><td>Бинарное потоковое шифрование <code>MONICA_ENC_V1</code></td><td>Скомпрометированные серверы WebDAV, атаки «человек посередине» (MITM), утечки данных из облачных хранилищ</td></tr></tbody></table>`,22))])}const E=o(p,[["render",c]]);export{_ as __pageData,E as default};
